#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char str[N + 1];
        scanf("%s", str);
        int min_importance = N;
        for (int i = 0; i <= N - K; i++) {
            int importance = 0;
            for (int j = i; j < i + K; j++) {
                for (int k = j; k < N; k++) {
                    if (str[j] == 'X' && str[k] == 'Z' && (k - j + 1) % 3 == 0) {
                        importance++;
                    }
                }
            }
            min_importance = (importance < min_importance) ? importance : min_importance;
        }
        printf("%d\n", min_importance);
    }
    return 0;
}

